--
-- Table structure for table `boards`
--

DROP TABLE IF EXISTS `boards`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `boards` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `workspace_id` bigint(20) unsigned NOT NULL,
  `name` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `cover_type` varchar(255) NOT NULL DEFAULT 'color',
  `cover_value` varchar(2048) DEFAULT NULL,
  `background_type` varchar(255) NOT NULL DEFAULT 'color',
  `background_value` varchar(255) NOT NULL DEFAULT '#6366f1',
  `visibility` enum('private','workspace','public') NOT NULL DEFAULT 'workspace',
  `member_permissions` varchar(255) NOT NULL DEFAULT 'members',
  `card_covers_enabled` tinyint(1) NOT NULL DEFAULT 1,
  `notifications_enabled` tinyint(1) NOT NULL DEFAULT 1,
  `browser_notifications_enabled` tinyint(1) NOT NULL DEFAULT 0,
  `attach_edit_activity_enabled` tinyint(1) NOT NULL DEFAULT 0,
  `is_starred` tinyint(1) NOT NULL DEFAULT 0,
  `is_archived` tinyint(1) NOT NULL DEFAULT 0,
  `is_hidden` tinyint(1) NOT NULL DEFAULT 0,
  `is_template` tinyint(1) NOT NULL DEFAULT 0,
  `created_by` bigint(20) unsigned NOT NULL,
  `position` int(11) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `boards_slug_unique` (`slug`),
  KEY `boards_workspace_id_index` (`workspace_id`),
  KEY `boards_created_by_index` (`created_by`),
  KEY `boards_workspace_id_is_archived_index` (`workspace_id`,`is_archived`),
  KEY `boards_is_starred_index` (`is_starred`),
  CONSTRAINT `boards_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `boards_workspace_id_foreign` FOREIGN KEY (`workspace_id`) REFERENCES `workspaces` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=45 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

